import (
	context "context"
	fern "github.com/oauth-client-credentials-openapi/fern"
	fernclient "github.com/oauth-client-credentials-openapi/fern/client"
	option "github.com/oauth-client-credentials-openapi/fern/option"
)

client := fernclient.NewClient(
	option.WithClientCredentials(
		"<YOUR_CLIENT_ID>",
		"<YOUR_CLIENT_SECRET>",
	),
)
response, err := client.Identity.GetToken(
	context.TODO(),
	&fern.GetTokenIdentityRequest{
		Username: "username",
		Password: "password",
	},
)

